using Microsoft.VisualStudio.TestTools.UnitTesting;

[TestClass]
public sealed class SampleTests
{
    private readonly TestContext _testContext;
    private readonly FakeService _service;

    public SampleTests(TestContext testContext)
    {
        _testContext = testContext;
        _service = new FakeService(); // sync init in constructor
    }

    [TestInitialize]
    public async Task InitAsync()
    {
        // Use TestInitialize ONLY for async setup
        await _service.ConnectAsync();
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task GetData_ReturnsResult()
    {
        var result = await _service.GetDataAsync(_testContext.CancellationToken);
        Assert.IsNotNull(result);
    }

    [TestCleanup]
    public void Cleanup() => _service.Reset();
}

// Stub service for demonstration
public class FakeService
{
    public Task ConnectAsync() => Task.CompletedTask;
    public Task<string> GetDataAsync(CancellationToken ct) => Task.FromResult("data");
    public void Reset() { }
}

